import { React, useState } from "react";
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
const AddTodoModal = () => {
    const [todoData, setTodoData] = useState({
        title:"",
        description:""
    })

const handleTitleChange = (e) => {
    setTodoData((prev)=>{
        return {...prev,title:e.target.value}
    })
}

const handleDescChange = (e) => {
    setTodoData((prev)=>{
        return {...prev,description:e.target.value}
    })
}

const handleSubmit=()=>{
    const {title, description} = todoData;
    if(title==="" || description===""){
        toast.error("Todo and description is required")
        return
    }
    toast.success("Todo Added")
    return
}

const handleClose=()=>{
    setTodoData({
        title:"",
        description:""
    })
}

    console.log(todoData)
    return(
    <div className="modal fade" id = "exampleModal">
        <ToastContainer autoClose={1000}/>
        <div className="modal-dialog" role="document">
            <div className="modal-content">
                <div className="modal-header">
                    <h5 className="modal-title">Add Todo</h5>
                    <button type="button" className="btn-close" data-bs-dismiss="modal" aria-label="Close">
                    <span aria-hidden="true" />
                    </button>
                </div>
                <div className="modal-body">
                    <div className = "form-group">
                        <input type="text" placeholder="Title" className="form-control" value={todoData.title} onChange={handleTitleChange} />
                        <textarea placeholder="Description" className="form-control mt-4" rows={3} value={todoData.description} onChange = {handleDescChange} ></textarea>
                    </div>
                </div>
                <div className="modal-footer">
                    <button type="button" className="btn btn-primary" onClick={handleSubmit}>Save Todo</button>
                    <button type="button" className="btn btn-secondary" data-bs-dismiss="modal" onClick={handleClose}>Close</button>
                </div>
            </div>
        </div>
    </div>
    )
}

export default AddTodoModal;
